        }
        System.out.println();

        // Test 4: Get by ID
        System.out.println("TEST 4: Get by ID");
        DesignModel loaded = storage.getDesignById(design1.getDesignId());
        System.out.println("✓ Loaded: " + loaded.getDesignName() +
                " (" + loaded.getFurnitureItems().size() + " items)\n");

        // Test 5: Update
        System.out.println("TEST 5: Update design");
        design1.setDesignName("Updated Living Room");
        storage.updateDesign(design1);
        System.out.println("✓ Updated design name\n");

        // Test 6: Delete
        System.out.println("TEST 6: Delete design");
        storage.deleteDesign(design2.getDesignId());
        System.out.println("✓ Deleted design2");

        // Test 7: Verify
        System.out.println("\nTEST 7: Verify count");
        List<DesignModel> remaining = storage.getDesignsByUserId(userId);
        System.out.println("✓ Remaining designs: " + remaining.size());

        System.out.println("\n=== ALL TESTS PASSED ===");
    }
}
