            JOptionPane.showMessageDialog(this, 
                "Login successful!\n\nWelcome " + Session.getInstance().getCurrentUser().getFullName() + 
                "\n\nThe main app window will open when fully integrated.",
                "Login Success", 
                JOptionPane.INFORMATION_MESSAGE);

            // You can uncomment this once MainFrame is compiled:
            // com.teamname.furniviz.app.MainFrame mainFrame = new com.teamname.furniviz.app.MainFrame();
            // mainFrame.setVisible(true);
            // LoginFrame.this.dispose();
        });
    }

    public void showLoginPanel() {
        cardLayout.show(cardPanel, "LOGIN");
        loginPanel.clearForm();
    }

    public void showRegistrationPanel() {
        cardLayout.show(cardPanel, "REGISTER");
        registrationPanel.clearForm();
    }
}

package com.teamname.furniviz.auth;

import javax.swing.*;
import java.awt.*;

public class LoginFrame extends JFrame {
    private CardLayout cardLayout;
    private JPanel cardPanel;
    private LoginPanel loginPanel;
    private RegistrationPanel registrationPanel;

    public LoginFrame() {
        super("Furniture Visualizer - Login");
        setSize(600, 600);
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setLocationRelativeTo(null);
        setResizable(false);

        cardLayout = new CardLayout();
        cardPanel = new JPanel(cardLayout);

        loginPanel = new LoginPanel(
                this::handleLoginSuccess,
                () -> cardLayout.show(cardPanel, "REGISTER")
        );

        registrationPanel = new RegistrationPanel(
                () -> cardLayout.show(cardPanel, "LOGIN"),
                () -> cardLayout.show(cardPanel, "LOGIN")
        );

        cardPanel.add(loginPanel, "LOGIN");
        cardPanel.add(registrationPanel, "REGISTER");

        add(cardPanel, BorderLayout.CENTER);

        cardLayout.show(cardPanel, "LOGIN");
    }

    private void handleLoginSuccess() {
        SwingUtilities.invokeLater(() -> {
            try {
                // Get the current logged-in user
                com.teamname.furniviz.accounts.User user = Session.getInstance().getCurrentUser();

                if (user != null) {
                    System.out.println("[OK] Transitioning to MainFrame for user: " + user.getEmail());

                    // Create and show the main application frame
                    com.teamname.furniviz.app.MainFrame mainFrame = new com.teamname.furniviz.app.MainFrame();
                    mainFrame.setVisible(true);

                    // Close the login frame
                    LoginFrame.this.dispose();
                } else {
                    JOptionPane.showMessageDialog(this, 
                        "Error: User session not found.",
                        "Login Error", 
                        JOptionPane.ERROR_MESSAGE);
                }
            } catch (Exception e) {
                System.err.println("[ERROR] Failed to transition to MainFrame: " + e.getMessage());
                e.printStackTrace();
                JOptionPane.showMessageDialog(this, 
                    "Error opening main application: " + e.getMessage(),
                    "Error", 
                    JOptionPane.ERROR_MESSAGE);
            }
        });
    }

    public void showLoginPanel() {
        cardLayout.show(cardPanel, "LOGIN");
        loginPanel.clearForm();
    }

    public void showRegistrationPanel() {
        cardLayout.show(cardPanel, "REGISTER");
        registrationPanel.clearForm();
    }
}

package com.teamname.furniviz.common.util;

public class ValidationUtil {
    private static final String EMAIL_PATTERN = "^[A-Za-z0-9._%-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$";

    public static boolean isValidEmail(String email) {
        if (email == null || email.isEmpty()) {
            return false;
        }
        return email.matches(EMAIL_PATTERN);
    }

    public static boolean isValidPassword(String password) {
        if (password == null || password.length() < 6) {
            return false;
        }

        boolean hasLetter = password.matches(".*[a-zA-Z].*");
        boolean hasDigit = password.matches(".*\\d.*");

        return hasLetter && hasDigit;
    }

    public static boolean isValidName(String name) {
        if (name == null || name.trim().isEmpty()) {
            return false;
        }
        return name.matches("^[a-zA-Z\\s\\-']+$") && name.trim().length() >= 2;
    }

    public static String sanitizeInput(String input) {
        if (input == null) {
            return "";
        }
        return input.trim();
    }

    public static String getEmailErrorMessage(String email) {
        if (email == null || email.isEmpty()) {
            return "Email is required";
        }
        if (!isValidEmail(email)) {
            return "Invalid email format";
        }
        return null;
    }

    public static String getPasswordErrorMessage(String password) {
        if (password == null || password.isEmpty()) {
            return "Password is required";
        }
        if (password.length() < 6) {
            return "Password must be at least 6 characters";
        }
        if (!password.matches(".*[a-zA-Z].*")) {
            return "Must contain a letter (a-z or A-Z)";
        }
        if (!password.matches(".*\\d.*")) {
            return "Must contain a number (0-9)";
        }
        return null;
    }

    public static String getNameErrorMessage(String name) {
        if (name == null || name.trim().isEmpty()) {
            return "Name is required";
        }
        if (name.trim().length() < 2) {
            return "Name must be at least 2 characters";
        }
        if (!isValidName(name)) {
            return "Name can only contain letters, spaces, hyphens, and apostrophes";
        }
        return null;
    }
}

